// Normalize the quiz.html POST payload
const input = $input.first().json;
const body = input.body || input;

return {
  json: {
    email:          body.email          || '',
    firstName:      body.firstName      || '',
    lastName:       body.lastName       || '',
    phone:          body.phone          || '',
    overall:        parseInt(body.overall) || 0,
    tier:           body.tier           || 'starter',
    categoryScores: body.categoryScores || {},
    weakestCategory:body.weakestCategory|| 'operations',
    industry:       body.industry       || '',
    revenue:        body.revenue        || '',
    timeline:       body.timeline       || '',
    source:         body.source         || 'maxxam-quiz',
    completedAt:    body.completedAt    || new Date().toISOString()
  }
};

// Map quiz.html pre-calculated scores to routing + CRM fields
const d = $input.first().json;

const overall        = d.overall || 0;
const tier           = d.tier || 'starter';
const categoryScores = d.categoryScores || {};
const weakestCat     = d.weakestCategory || 'operations';

// ── Tier → lead temperature ──────────────────────────────
let categoryTag, category, primaryCTA, emailSequence;
if (tier === 'advanced') {
  categoryTag   = 'hot-lead';
  category      = 'Automation Advanced';
  primaryCTA    = 'Book Your Free Discovery Call';
  emailSequence = '4 emails / 7 days';
} else if (tier === 'building') {
  categoryTag   = 'warm-lead';
  category      = 'Automation Builder';
  primaryCTA    = 'Book Your Free Discovery Call';
  emailSequence = '7 emails / 14 days';
} else {
  if (overall <= 25) {
    categoryTag   = 'cold-lead';
    category      = 'Automation Starter';
    primaryCTA    = 'Explore Free Resources';
    emailSequence = '1 email + monthly';
  } else {
    categoryTag   = 'cool-lead';
    category      = 'Automation Starter';
    primaryCTA    = 'Book Your Free Discovery Call';
    emailSequence = '4 emails + weekly';
  }
}

// ── Tags ─────────────────────────────────────────────────
const tags = [];

const ind = (d.industry || '').toLowerCase();
let industryTag = 'other-service';
if      (ind.includes('health') || ind.includes('dental') || ind.includes('mental')) industryTag = 'healthcare';
else if (ind.includes('hvac')   || ind.includes('plumbing') || ind.includes('roofing')) industryTag = 'home-services';
else if (ind.includes('med spa')|| ind.includes('wellness') || ind.includes('beauty')) industryTag = 'wellness';
else if (ind.includes('e-commerce') || ind.includes('ecommerce')) industryTag = 'ecommerce';
else if (ind.includes('coaching') || ind.includes('consulting')) industryTag = 'coach-consultant';
else if (ind.includes('restaurant') || ind.includes('food')) industryTag = 'food-service';
tags.push(industryTag);

const rev = (d.revenue || '').toLowerCase();
let revenueTag = 'unknown';
if      (rev.includes('50k'))  revenueTag = 'startup';
else if (rev.includes('100k') || rev.includes('250k')) revenueTag = 'emerging';
else if (rev.includes('251k') || rev.includes('350k')) revenueTag = 'growing';
else if (rev.includes('351k') || rev.includes('500k')) revenueTag = 'established';
else if (rev.includes('501k') || rev.includes('750k')) revenueTag = 'scaling';
else if (rev.includes('above') || rev.includes('750k')) revenueTag = 'enterprise';
tags.push(revenueTag);

const tl = (d.timeline || '').toLowerCase();
let timelineTag = 'timeline-someday';
if      (tl.includes('yesterday')) timelineTag = 'timeline-urgent';
else if (tl.includes('30'))        timelineTag = 'timeline-now';
else if (tl.includes('60'))        timelineTag = 'timeline-soon';
else if (tl.includes('90'))        timelineTag = 'timeline-quarter';
else if (tl.includes('120'))       timelineTag = 'timeline-later';
tags.push(timelineTag);

tags.push('weak-' + weakestCat);
tags.push(categoryTag);
if (d.source) tags.push('source-' + d.source.toLowerCase().replace(/\s+/g, '-'));

// ── Category score string ────────────────────────────────
const catLabels = {
  visibility: 'Visibility', trust: 'Trust', revenue: 'Revenue',
  scale: 'Scale', operations: 'Operations', mindset: 'Mindset'
};
const catScoreStr = Object.entries(categoryScores)
  .map(([k, v]) => (catLabels[k] || k) + ': ' + v + '%')
  .join(' | ');

const weakestCatLabel = catLabels[weakestCat] || weakestCat;

return {
  json: {
    // Contact
    email:           d.email,
    firstName:       d.firstName,
    lastName:        d.lastName || '',
    phone:           d.phone || '',
    submissionId:    'sub_' + Date.now(),
    timestamp:       d.completedAt || new Date().toISOString(),

    // Scores (totalScore = overall % for downstream compat)
    totalScore:          overall,
    overall:             overall,
    tier:                tier,
    categoryScores:      categoryScores,
    catScoreStr:         catScoreStr,
    weakestCategory:     weakestCat,
    weakestCategoryLabel:weakestCatLabel,

    // Routing
    category:       category,
    categoryTag:    categoryTag,
    primaryCTA:     primaryCTA,
    emailSequence:  emailSequence,

    // Context
    industry:  d.industry  || '',
    revenue:   d.revenue   || '',
    timeline:  d.timeline  || '',
    source:    d.source    || '',

    // Tags
    allTags:    tags.join(', '),
    tagsArray:  tags,
    industryTag:industryTag,
    revenueTag: revenueTag,
    timelineTag:timelineTag,

    // Filler fields (downstream compat)
    painScore:            overall,
    buyingReadinessScore: overall,
    missingSystemsCount:  0,
    missingSystemsList:   '',
    toolsCount:           0,
    toolsUsed:            '',
    utmSource:            '',
    utmMedium:            '',
    utmCampaign:          ''
  }
};

const d = $input.first().json;

const calLink    = 'https://tinyurl.com/maxxam-call';
const brandGold  = '#FCC01E';
const brandBlack = '#1a1a1a';

// Tier headline / sub
const tierContent = {
  advanced: {
    headline: 'Strong foundation. Let\'s build the next layer.',
    sub: 'You\'re operating with more structure than most. The opportunity now is to layer in intelligent automation — AI-assisted engagement, predictive follow-up, and systems that optimize over time.'
  },
  building: {
    headline: 'You\'ve got the right instincts. Time to close the gaps.',
    sub: 'You have some systems in place, but they\'re not working together as one coordinated engine yet. Closing your lowest-scoring areas will create a compounding effect across your entire business.'
  },
  starter: {
    headline: 'Every system you build will have immediate, measurable impact.',
    sub: 'You\'re early in your automation journey — which means the ROI on every system we build is instant and clear. The gaps you have right now are costing you time and revenue, and they\'re all fixable.'
  }
};
const tc = tierContent[d.tier] || tierContent.starter;

// Category bars HTML
const catMeta = [
  { key: 'visibility',  label: 'Visibility'  },
  { key: 'trust',       label: 'Trust'       },
  { key: 'revenue',     label: 'Revenue'     },
  { key: 'scale',       label: 'Scale'       },
  { key: 'operations',  label: 'Operations'  },
  { key: 'mindset',     label: 'Mindset'     }
];

function barColor(pct) {
  if (pct <= 45) return '#ef4444';
  if (pct <= 70) return brandGold;
  return '#22c55e';
}

const catBarsHtml = catMeta.map(c => {
  const pct = d.categoryScores[c.key] || 0;
  const isWeakest = c.key === d.weakestCategory;
  const color = barColor(pct);
  return `
    <tr>
      <td style="padding:6px 0; font-size:13px; font-weight:${isWeakest ? '700' : '500'}; color:${isWeakest ? brandBlack : '#444'}; white-space:nowrap; padding-right:12px;">
        ${isWeakest ? '⚠️ ' : ''}${c.label}
      </td>
      <td style="width:100%;">
        <div style="background:#e5e7eb; border-radius:4px; height:10px; overflow:hidden;">
          <div style="background:${color}; width:${pct}%; height:100%; border-radius:4px;"></div>
        </div>
      </td>
      <td style="padding-left:10px; font-size:13px; font-weight:700; color:${color}; white-space:nowrap;">${pct}%</td>
    </tr>`;
}).join('');

// Next steps by tier
const nextSteps = d.tier === 'advanced'
  ? ['Review your highest-leverage integration gaps', 'Explore AI-assisted engagement systems', 'Book a strategy call to map the next revenue layer', 'Consider multi-channel automation to protect market position']
  : d.tier === 'building'
  ? ['Focus first on your weakest category: ' + d.weakestCategoryLabel, 'Connect your existing tools into a unified workflow', 'Build automated follow-up for leads that go cold', 'Book a free call to turn this score into a 90-day plan']
  : ['Start with ONE system in your weakest area: ' + d.weakestCategoryLabel, 'Document your most repeated task and automate it first', 'Set up basic lead capture before anything else', 'Book a free diagnostic call — no commitment, just clarity'];

const stepsHtml = nextSteps.map((s, i) => `<li style="padding:10px 14px; background:#fff; margin-bottom:8px; border-radius:6px; border-left:4px solid ${brandGold}; font-size:14px; color:#333;"><strong>${i+1}.</strong> ${s}</li>`).join('');

const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    * { margin:0; padding:0; box-sizing:border-box; }
    body { font-family: -apple-system, Helvetica, Arial, sans-serif; background:#fff; color:#1a1a1a; }
    .container { max-width:760px; margin:0 auto; padding:36px; }
  </style>
</head>
<body>
<div class="container">

  <!-- Header -->
  <div style="text-align:center; padding:28px 32px; background:linear-gradient(135deg,#1a1a1a 0%,#2d2d2d 100%); border-radius:12px; margin-bottom:24px;">
    <div style="font-size:26px; font-weight:700; color:${brandGold}; letter-spacing:-0.02em;">MAXXAM AI</div>
    <div style="color:#ccc; font-size:12px; margin-top:4px;">AI Readiness Scorecard — Personal Results</div>
  </div>

  <!-- Score Ring + Tier -->
  <div style="text-align:center; padding:32px; background:linear-gradient(135deg,${brandGold} 0%,#e6ac00 100%); border-radius:12px; margin-bottom:24px;">
    <div style="font-size:13px; font-weight:600; color:${brandBlack}; letter-spacing:0.08em; text-transform:uppercase; margin-bottom:8px;">Overall AI Readiness</div>
    <div style="font-size:64px; font-weight:800; color:${brandBlack}; line-height:1;">${d.overall}<span style="font-size:28px;">%</span></div>
    <div style="display:inline-block; margin-top:16px; padding:8px 22px; background:${brandBlack}; color:${brandGold}; border-radius:50px; font-size:15px; font-weight:600;">${d.category}</div>
  </div>

  <!-- Headline / Sub -->
  <div style="background:#f8f9fa; border-radius:10px; padding:24px 28px; margin-bottom:24px;">
    <div style="font-size:18px; font-weight:700; color:${brandBlack}; margin-bottom:10px;">${tc.headline}</div>
    <div style="font-size:14px; color:#555; line-height:1.75;">${tc.sub}</div>
  </div>

  <!-- Category Bars -->
  <div style="background:#f8f9fa; border-radius:10px; padding:24px 28px; margin-bottom:24px;">
    <div style="font-size:15px; font-weight:700; color:${brandBlack}; margin-bottom:16px;">📊 Score by Category</div>
    <table style="width:100%; border-collapse:collapse;">
      ${catBarsHtml}
    </table>
    <div style="margin-top:14px; padding:12px 16px; background:#fff3cd; border-radius:6px; font-size:13px; color:#92400e;">
      ⚠️ <strong>Priority gap:</strong> Your lowest score is <strong>${d.weakestCategoryLabel}</strong> — that's where we start.
    </div>
  </div>

  <!-- Next Steps -->
  <div style="background:#f8f9fa; border-radius:10px; padding:24px 28px; margin-bottom:24px;">
    <div style="font-size:15px; font-weight:700; color:${brandBlack}; margin-bottom:14px;">🎯 Your Next Steps</div>
    <ul style="list-style:none; padding:0;">
      ${stepsHtml}
    </ul>
  </div>

  <!-- Business Profile -->
  <div style="background:#f8f9fa; border-radius:10px; padding:24px 28px; margin-bottom:24px;">
    <div style="font-size:15px; font-weight:700; color:${brandBlack}; margin-bottom:14px;">👤 Your Business Profile</div>
    <table style="width:100%; border-collapse:collapse; font-size:14px;">
      <tr><td style="padding:6px 0; color:#555; width:40%;">Industry</td><td style="font-weight:500;">${d.industry || '—'}</td></tr>
      <tr><td style="padding:6px 0; color:#555;">Annual Revenue</td><td style="font-weight:500;">${d.revenue || '—'}</td></tr>
      <tr><td style="padding:6px 0; color:#555;">Implementation Timeline</td><td style="font-weight:500;">${d.timeline || '—'}</td></tr>
      <tr><td style="padding:6px 0; color:#555;">How You Found Us</td><td style="font-weight:500;">${d.source || '—'}</td></tr>
    </table>
  </div>

  <!-- CTA -->
  <div style="text-align:center; padding:32px; background:${brandBlack}; border-radius:12px;">
    <div style="font-size:20px; font-weight:700; color:#fff; margin-bottom:10px;">Ready to close the gaps?</div>
    <div style="font-size:14px; color:#ccc; margin-bottom:20px; line-height:1.7;">Book a free discovery call with Reginald. We'll map out exactly which systems to build first — and what the ROI looks like for your business.</div>
    <a href="${calLink}" style="display:inline-block; padding:14px 36px; background:${brandGold}; color:${brandBlack}; text-decoration:none; border-radius:50px; font-weight:700; font-size:15px;">${d.primaryCTA}</a>
    <div style="margin-top:10px; font-size:11px; color:#888;">${calLink}</div>
  </div>

  <!-- Footer -->
  <div style="text-align:center; padding:24px; color:#999; font-size:11px; margin-top:16px;">
    <p>© ${new Date().getFullYear()} MAXXAM AI · Newnan, Georgia · maxxam.ai</p>
    <p>Questions? Reply to this email — Reggie reads every one.</p>
  </div>

</div>
</body>
</html>`;

return { json: { ...d, pdfHtml: html, calLink } };
